export type InlineAlertType = 'error' | 'success' | 'warning' | 'info' | 'neutral';

export interface InlineAlertOptions {
  type?: InlineAlertType;
  message?: string;
  id?: string;
}

const DEFAULT_ERROR_MESSAGE = 'Form field value is invalid';

/**
 * Creates an inline alert element with icon and optional message.
 * Used below form inputs for validation messages, and reusable in
 * any context that needs a compact icon + message status indicator.
 */
export function createInlineAlert(options: InlineAlertOptions = {}): HTMLDivElement {
  const { type = 'error', message, id } = options;

  const el = document.createElement('div');
  el.className = `arvo-inline-alert arvo-inline-alert--${type}`;
  el.setAttribute('role', 'alert');
  if (id) el.id = id;

  const ico = document.createElement('span');
  ico.className = 'arvo-inline-alert__ico';
  ico.setAttribute('aria-hidden', 'true');
  el.appendChild(ico);

  const msg = document.createElement('span');
  msg.className = 'arvo-inline-alert__msg';
  msg.textContent = message ?? '';
  el.appendChild(msg);

  return el;
}

/**
 * Updates an existing inline alert's message and/or type.
 */
export function updateInlineAlert(
  el: HTMLElement,
  options: Partial<InlineAlertOptions>
): void {
  if (options.type !== undefined) {
    el.className = `arvo-inline-alert arvo-inline-alert--${options.type}`;
  }
  if (options.message !== undefined) {
    const msg = el.querySelector('.arvo-inline-alert__msg');
    if (msg) msg.textContent = options.message;
  }
}

/**
 * Returns the default error message used when no custom message is configured.
 */
export function getDefaultErrorMsg(): string {
  return DEFAULT_ERROR_MESSAGE;
}

export interface ErrorTooltipIconOptions {
  /** Tooltip text shown on hover and used for aria-describedby on the input. */
  tooltip?: string;
}

/**
 * Creates an error tooltip icon element for placement inside a form input field.
 * Hidden by default; made visible via CSS when the parent has `.has-error.error-tooltip`.
 */
export function createErrorTooltipIcon(options: ErrorTooltipIconOptions = {}): HTMLSpanElement {
  const ico = document.createElement('span');
  ico.className = 'arvo-err-ico';
  ico.setAttribute('aria-hidden', 'true');

  const tooltip = options.tooltip ?? DEFAULT_ERROR_MESSAGE;
  ico.setAttribute('aria-label', tooltip);

  return ico;
}

/**
 * Updates the tooltip text on an error tooltip icon.
 */
export function updateErrorTooltipIcon(
  ico: HTMLSpanElement,
  tooltip: string
): void {
  ico.setAttribute('aria-label', tooltip);
}
